// === TEST CASES ===
// TC1: input { monthlyUsers:3, monthlyQueries:100, plan:"basic", advancedAnalytics:false } → output { total: 0.1, breakdown: {...} }
// TC2: input { monthlyUsers:10, monthlyQueries:5000, plan:"basic", advancedAnalytics:false } → output { total: 55, breakdown: {...} }
// TC3: input { monthlyUsers:20, monthlyQueries:10000, plan:"pro", advancedAnalytics:false } → output { total: 264, breakdown: {...} }
// TC4: input { monthlyUsers:100, monthlyQueries:500000, plan:"enterprise", advancedAnalytics:true } → output { total: 949, breakdown: {...} }
// TC5: input { monthlyUsers:0, monthlyQueries:0, plan:"basic", advancedAnalytics:false } → output { total: 0, breakdown: {...} }
// TC6: input { monthlyUsers:-1, monthlyQueries:100, plan:"basic", advancedAnalytics:false } → output { error: "Monthly users must be non-negative" }
// TC7: input { monthlyUsers:10, monthlyQueries:-100, plan:"basic", advancedAnalytics:false } → output { error: "Monthly queries must be non-negative" }
// TC8: input { monthlyUsers:10, monthlyQueries:100, plan:"premium", advancedAnalytics:false } → output { error: "Invalid plan option" }
// TC9: input { monthlyUsers:10, monthlyQueries:100, advancedAnalytics:false } → output { error: "Plan is required" }
// TC10: input { monthlyUsers:1000000, monthlyQueries:10000000000, plan:"enterprise", advancedAnalytics:true } → output { total: 7000349, breakdown: {...} }
// TC11: input { monthlyUsers:"abc", monthlyQueries:100, plan:"basic", advancedAnalytics:false } → output { error: "Monthly users must be a number" }
// TC12: input { monthlyUsers:true, monthlyQueries:100, plan:"basic", advancedAnalytics:false } → output { error: "Monthly users must be a number" }
// TC13: input undefined → output { error: "Inputs are required" }
// TC14: input { monthlyUsers:20, monthlyQueries:10000, plan:" Pro ", advancedAnalytics:false } → output { total: 264, breakdown: {...} }
// TC15: input { monthlyUsers:100, monthlyQueries:500000, plan:"ENTERPRISE", advancedAnalytics:true } → output { total: 949, breakdown: {...} }
// TC16: input { monthlyUsers:20, monthlyQueries:10000, plan:"pro", advancedAnalytics:"true" } → output { error: "Advanced analytics must be a boolean" }
// TC17: input { monthlyUsers:20, monthlyQueries:10000, plan:"pro" } → output { total: 264, breakdown: {...} } (missing advancedAnalytics defaults to false)
// TC18: input { monthlyUsers:NaN, monthlyQueries:100, plan:"basic", advancedAnalytics:false } → output { error: "Monthly users must be a number" }
// TC19: input { monthlyUsers:10, monthlyQueries:100, plan:"", advancedAnalytics:false } → output { error: "Plan is required" }
// TC20: input { monthlyUsers:10, monthlyQueries:100, plan:"pro_plus", advancedAnalytics:false } → output { error: "Invalid plan option" }
// TC21: input { monthlyUsers:0, monthlyQueries:1000, plan:"pro", advancedAnalytics:false } → output { total: 99.5, breakdown: {...} }

const calculator = {
  // Plan configurations with base cost, free users, per-user rate, per-query rate
  PLANS: {
    basic:   { base: 0,   freeUsers: 5, userRate: 10, queryRate: 0.001  },
    pro:     { base: 99,  freeUsers: 0, userRate: 8,  queryRate: 0.0005 },
    enterprise: { base: 299, freeUsers: 0, userRate: 5, queryRate: 0.0002 }
  },
  ANALYTICS_COST: 50,

  calculate(inputs) {
    // Run validation first
    const validationResult = this.validate(inputs);
    if (validationResult.error) {
      return validationResult;
    }

    // Normalize and extract parameters (defaults applied for missing optional fields)
    const users = Number(inputs.monthlyUsers) || 0;
    const queries = Number(inputs.monthlyQueries) || 0;
    const planKey = String(inputs.plan).trim().toLowerCase();
    const analyticsEnabled = inputs.advancedAnalytics === true;

    const plan = this.PLANS[planKey];

    // User cost (charge for users above free allowance)
    let userCost = 0;
    const chargeableUsers = Math.max(0, users - plan.freeUsers);
    userCost = chargeableUsers * plan.userRate;

    // Query cost
    const queryCost = queries * plan.queryRate;

    // Base cost from plan
    const baseCost = plan.base;

    // Analytics add-on
    const analyticsCost = analyticsEnabled ? this.ANALYTICS_COST : 0;

    // Total
    const exactTotal = baseCost + userCost + queryCost + analyticsCost;
    // Round to cents to avoid floating point display issues
    const round = (n) => Math.round(n * 100) / 100;
    const total = round(exactTotal);

    const breakdown = {
      baseCost: baseCost,
      userCost: round(userCost),
      queryCost: round(queryCost),
      analyticsCost: analyticsCost,
      total: total
    };

    return { total: total, breakdown: breakdown };
  },

  validate(inputs) {
    const errors = [];

    // Input presence and type
    if (!inputs || typeof inputs !== 'object') {
      return { error: 'Inputs are required' };
    }

    // monthlyUsers validation
    const users = inputs.monthlyUsers;
    if (users !== undefined && users !== null) {
      if (typeof users !== 'number' || isNaN(users)) {
        errors.push('Monthly users must be a number');
      } else if (users < 0) {
        errors.push('Monthly users must be non-negative');
      }
    } // else optional, will default to 0

    // monthlyQueries validation
    const queries = inputs.monthlyQueries;
    if (queries !== undefined && queries !== null) {
      if (typeof queries !== 'number' || isNaN(queries)) {
        errors.push('Monthly queries must be a number');
      } else if (queries < 0) {
        errors.push('Monthly queries must be non-negative');
      }
    } // else optional

    // plan validation
    const plan = inputs.plan;
    if (plan === undefined || plan === null || String(plan).trim() === '') {
      errors.push('Plan is required');
    } else {
      const normalized = String(plan).trim().toLowerCase();
      if (!this.PLANS[normalized]) {
        errors.push('Invalid plan option');
      }
    }

    // advancedAnalytics validation
    const analytics = inputs.advancedAnalytics;
    if (analytics !== undefined && analytics !== null) {
      if (typeof analytics !== 'boolean') {
        errors.push('Advanced analytics must be a boolean');
      }
    } // else missing means false, allowed

    if (errors.length > 0) {
      return { error: errors.join('; ') };
    }

    return {}; // valid
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'monthlyUsers',
    label: 'Monthly Active Users',
    type: 'number',
    placeholder: 'e.g. 50',
    step: 1
  },
  {
    name: 'monthlyQueries',
    label: 'Monthly Queries (estimated)',
    type: 'number',
    placeholder: 'e.g. 10000',
    step: 1
  },
  {
    name: 'plan',
    label: 'Plan Tier',
    type: 'select',
    options: [
      ['basic', '🧪 Basic'],
      ['pro', '⚡ Pro'],
      ['enterprise', '🏢 Enterprise']
    ]
  },
  {
    name: 'advancedAnalytics',
    label: 'Advanced Analytics (add‑on)',
    type: 'checkbox'
  }
];
